--
-- Triggers `certificates`
--
DELIMITER $$
CREATE TRIGGER `before_cert_issued` BEFORE UPDATE ON `certificates` FOR EACH ROW BEGIN
    IF NEW.status = 'issued' AND OLD.status != 'issued' THEN
        SET NEW.attendance_rate = (
            SELECT ROUND((SUM(a.status IN ('present','late')) / COUNT(a.id)) * 100, 1)
            FROM enrollments e
            JOIN workshop_sessions ws ON ws.workshop_id = e.workshop_id
            LEFT JOIN attendance a ON a.session_id = ws.id AND a.user_id = e.user_id
            WHERE e.user_id = NEW.user_id AND e.workshop_id = NEW.workshop_id
        );
        SET NEW.issued_at = NOW();
    END IF;
END
$$
DELIMITER ;

